import { useEffect } from 'react';
import { getSocket } from '../utils/socket';
import useStore from '../store/useStore';

export const useSocket = () => {
  const { addMessage, updateMessage, updateTask, addDecision,
          setTyping, activeChannel } = useStore();

  useEffect(() => {
    const socket = getSocket();
    if (!socket) return;

    const onNewMessage = (msg) => addMessage(msg);
    const onResolved  = (msg) => updateMessage(msg);
    const onTaskUp    = (task) => updateTask(task);
    const onTypingStart = ({ userId, userName, channelId }) => {
      if (channelId === activeChannel?._id)
        setTyping(channelId, userId, userName, true);
    };
    const onTypingStop = ({ userId, channelId }) => {
      setTyping(channelId, userId, null, false);
    };

    socket.on('message:new',      onNewMessage);
    socket.on('message:resolved', onResolved);
    socket.on('task:updated',     onTaskUp);
    socket.on('typing:start',     onTypingStart);
    socket.on('typing:stop',      onTypingStop);

    return () => {
      socket.off('message:new',      onNewMessage);
      socket.off('message:resolved', onResolved);
      socket.off('task:updated',     onTaskUp);
      socket.off('typing:start',     onTypingStart);
      socket.off('typing:stop',      onTypingStop);
    };
  }, [activeChannel, addMessage, updateMessage, updateTask, addDecision, setTyping]);
};
